from pathlib import Path
from datetime import datetime, timezone, timedelta

root = Path('/home/orbibot/.zeroclaw/workspace/company-wiki/raw')

def load(p):
    return json.loads(Path(p).read_text())

def iso_dt(s):
    if not s: return None
    return datetime.fromisoformat(s.replace('Z','+00:00'))

# GitHub recent repos
repo_data = load(root/'github/items/6b96ee4ef4fc8a456a4546cdf9d1f477b747aca86c0db0686d3da2702019a07c.json')
repos = repo_data['payload']
recent_repos = sorted(repos, key=lambda r: r.get('pushedAt') or '', reverse=True)[:12]
print('RECENT_GITHUB')
for r in recent_repos:
    print(json.dumps({k:r.get(k) for k in ['nameWithOwner','isPrivate','pushedAt','updatedAt','stargazerCount','forkCount','defaultBranchRef','url']}, ensure_ascii=False))

# Notion targeted data-source queries by source_id suffix or data_source_id
notion_dir = root/'notion/items'
targets = {
    'Action Items':'1b549045-5415-80db-844d-000bfda903e2',
    'Todo':'f3f4cb81-965d-4f30-952f-a7903737d6ad',
    'Sentry issue':'cfcc6420-eed5-4478-bac8-b731f1ee112d',
    'slow api':'3e9a1c1d-c66f-49c7-95dd-2b823bd684b3',
    'PRD':'1af49045-5415-8011-b3eb-000bd4d7f61b',
    '회의록':'a0e96802-dc9c-468a-b04c-b51bc1adb1db',
}
queries={}
for p in notion_dir.glob('*.json'):
    try: d=load(p)
    except: continue
    if d.get('payload_kind')!='data_source_query': continue
    dsid=d.get('payload',{}).get('data_source_id')
    for name,tid in targets.items():
        if dsid==tid:
            queries[name]=d

print('NOTION_TARGETS_FOUND', sorted(queries))
for name,d in queries.items():
    payload=d['payload']
    rows=payload.get('results',[])
    # extract title heuristically and any status-ish properties
    def extract(row):
        props=row.get('properties',{})
        title=None
        interesting={}
        for pk,pv in props.items():
            t=pv.get('type')
            val=pv.get(t)
            if t=='title':
                title=''.join(x.get('plain_text','') for x in val)
            elif t=='rich_text':
                txt=''.join(x.get('plain_text','') for x in val)
                if txt: interesting[pk]=txt[:80]
            elif t=='status' and val:
                interesting[pk]=val.get('name')
            elif t=='select' and val:
                interesting[pk]=val.get('name')
            elif t=='multi_select' and val:
                interesting[pk]=[x.get('name') for x in val]
            elif t=='checkbox':
                interesting[pk]=val
            elif t=='date' and val:
                interesting[pk]=val.get('start')
            elif t=='people' and val:
                interesting[pk]=len(val)
            elif t=='number' and val is not None:
                interesting[pk]=val
            elif t=='url' and val:
                interesting[pk]=val
        return {
            'title': title,
            'last_edited_time': row.get('last_edited_time'),
            'created_time': row.get('created_time'),
            'interesting': interesting,
        }
    top = sorted([extract(r) for r in rows], key=lambda x: x['last_edited_time'] or '', reverse=True)[:5]
    print('DATA_SOURCE', name, 'FETCHED_AT', payload.get('fetched_at'), 'ROW_COUNT', payload.get('row_count'))
    for item in top:
        print(json.dumps(item, ensure_ascii=False))

# Trello recent cards on Dev and 공지
boards = {
    'Dev': load(root/'trello/items/c6f5c3df45fb8311f0d7937043cf00a968a957ce89e50dc041ed5b318f4e9ffe.json')['payload'],
    '공지': load(root/'trello/items/588aac291e88f45a5e5d6df35aa9cfeefce1971c54247a852d5e3691f2c06a1e.json')['payload']
}
print('RECENT_TRELLO')
for bname,cards in boards.items():
    top=sorted(cards,key=lambda c:c.get('dateLastActivity') or '', reverse=True)[:8]
    print('BOARD',bname)
    for c in top:
        print(json.dumps({k:c.get(k) for k in ['name','dateLastActivity','url','idList']}, ensure_ascii=False))
